func TestNewXxx(t *testing.T) {
    type args struct {
        value string
    }
    type expected struct {
        wantErr bool
        errName string
    }

    tests := []struct {
        testName string
        args     args
        expected expected
    }{
        // 正常系
        {testName: "valid value", args: args{value: "valid"}, expected: expected{wantErr: false}},
        // 異常系
        {testName: "invalid format", args: args{value: "!!!"}, expected: expected{wantErr: true, errName: "ValidationError"}},
        // 境界値
        {testName: "max length", args: args{value: strings.Repeat("a", MaxLen)}, expected: expected{wantErr: false}},
        {testName: "over max length", args: args{value: strings.Repeat("a", MaxLen+1)}, expected: expected{wantErr: true, errName: "ValidationError"}},
        // 特殊文字
        {testName: "emoji", args: args{value: "Value 📋"}, expected: expected{wantErr: false}},
        {testName: "japanese", args: args{value: "バリュー"}, expected: expected{wantErr: false}},
        // 空文字
        {testName: "empty string", args: args{value: ""}, expected: expected{wantErr: true, errName: "ValidationError"}},
        {testName: "whitespace only", args: args{value: "   "}, expected: expected{wantErr: true, errName: "ValidationError"}},
        // Nil
        {testName: "zero value", args: args{value: ""}, expected: expected{wantErr: true, errName: "ValidationError"}},
    }

    for _, tt := range tests {
        t.Run(tt.testName, func(t *testing.T) {
            got, err := NewXxx(tt.args.value)
            if tt.expected.wantErr {
                if err == nil {
                    t.Fatal("expected error but got nil")
                }
                var appErr apperror.AppError
                if errors.As(err, &appErr) {
                    if diff := cmp.Diff(tt.expected.errName, appErr.ErrorName()); diff != "" {
                        t.Errorf("error name mismatch (-want +got):\n%s", diff)
                    }
                }
            } else {
                if err != nil {
                    t.Fatalf("unexpected error: %v", err)
                }
                _ = got
            }
        })
    }
}

func TestActionHandler(t *testing.T) {
    t.Run("2xx Success", func(t *testing.T) {
        tests := []struct {
            name     string
            setup    func(t *testing.T, q db.Querier) /* setup data */
            request  func() *http.Request
            expected struct {
                statusCode int
                /* response fields */
            }
        }{...}

        for _, tt := range tests {
            t.Run(tt.name, func(t *testing.T) {
                q := testutil.SetupTestTx(t)
                tt.setup(t, q)
                repo := task_repository.NewTaskRepository(q)
                handler := NewTaskHandler(repo).Action()

                w := httptest.NewRecorder()
                handler.ServeHTTP(w, tt.request())

                resp := w.Result()
                if diff := cmp.Diff(tt.expected.statusCode, resp.StatusCode); diff != "" {
                    t.Errorf("status code mismatch (-want +got):\n%s", diff)
                }
            })
        }
    })

    t.Run("4xx Error", func(t *testing.T) { /* error cases */ })
}
